// src/pages/gov/DonationsQueryPage.jsx
import { useState }   from "react";
import { useToast }   from "../../context/ToastContext";
import PageHeader     from "../../components/shared/PageHeader";
import DataTable      from "../../components/shared/DataTable";
import { donations }  from "../../data/mockData";

const fmt   = (n) => n?.toLocaleString() ?? "–";
const short = (s) => s?.length > 12 ? s.slice(0,12)+"…" : s;

export default function DonationsQueryPage() {
  const toast = useToast();
  const [donorId,  setDonorId]  = useState("");
  const [results,  setResults]  = useState(null);

  const query = () => {
    const r = donations.filter((d) => d.donor === donorId || !donorId);
    setResults(r);
    toast(`Found ${r.length} donation(s)`, "info");
  };

  return (
    <div>
      <PageHeader title="Donations Query" desc="Look up all donations made by a specific donor" />

      <div className="card" style={{ marginBottom:16 }}>
        <div style={{ display:"flex", gap:12, alignItems:"flex-end", flexWrap:"wrap" }}>
          <div className="form-group" style={{ flex:1, minWidth:180 }}>
            <label>Donor ID</label>
            <input value={donorId} onChange={(e) => setDonorId(e.target.value)} placeholder="e.g. DNR001 (empty = all)" />
          </div>
          <button className="btn btn-primary" onClick={query}>Query Ledger</button>
        </div>
      </div>

      {results !== null && (
        <div className="card">
          <div className="card-title" style={{ marginBottom:16 }}>Results · {results.length} record(s)</div>
          <DataTable
            columns={[
              { key:"id",     label:"ID",      mono:true },
              { key:"donor",  label:"Donor",   mono:true },
              { key:"fund",   label:"Fund",    mono:true },
              { key:"amount", label:"Amount",  render:(r) => <><span className="text-gold">◈</span> {fmt(r.amount)}</> },
              { key:"date",   label:"Date",    mono:true },
              { key:"tx",     label:"TX Hash", mono:true, render:(r) => short(r.tx) },
            ]}
            data={results}
            emptyText="No donations match this query"
          />
        </div>
      )}
    </div>
  );
}
